pub const SCR_W: usize = 800;
pub const SCR_H: usize = 480;

#[derive(Clone, Copy, PartialEq)]
pub enum Menu {
    ActiveStyle,
    AlignStyle,
    Alignment,
    Borders,
    CellStyle,
    Clickable,
    Cols,
    Complex,
    ContainerBg,
    ContainerBorder,
    DynAlign,
    DynUpdate,
    Dynamic,
    Fixed,
    FlushCells,
    FocusDisable,
    FocusGroups,
    Focusable,
    FontIcons,
    Hello,
    Icons,
    LeafStyle,
    Margin,
    MultilineAlign,
    Overload,
    Pad,
    Popup,
    Progress,
    Rows,
    Weighted,
}

static CURRENT_MENU: Mutex<Option<Menu>> = Mutex::new(None);
static FOCUSED: Mutex<Option<usize>> = Mutex::new(None);
static LAST_DRAWN_FOCUS: Mutex<Option<usize>> = Mutex::new(Some(usize::MAX));
use std::collections::HashSet;
use std::sync::LazyLock;
static ACTIVE: LazyLock<Mutex<HashSet<usize>>> = LazyLock::new(|| Mutex::new(HashSet::new()));
static LAST_DRAWN_ACTIVE: LazyLock<Mutex<HashSet<usize>>> = LazyLock::new(|| Mutex::new(HashSet::new()));

// Press coordinates: stored for callbacks that need click position
static PRESS_X: AtomicUsize = AtomicUsize::new(0);
static PRESS_RIGHT: AtomicUsize = AtomicUsize::new(0);
pub fn last_press() -> (usize, usize) { (PRESS_X.load(Ordering::Relaxed), PRESS_RIGHT.load(Ordering::Relaxed)) }

use std::sync::atomic::{AtomicUsize, Ordering};
static PROG_1_PREV: AtomicUsize = AtomicUsize::new(usize::MAX);
static PROG_2_PREV: AtomicUsize = AtomicUsize::new(usize::MAX);
static PROG_3_PREV: AtomicUsize = AtomicUsize::new(usize::MAX);
static PROG_4_PREV: AtomicUsize = AtomicUsize::new(usize::MAX);
static PROG_5_PREV: AtomicUsize = AtomicUsize::new(usize::MAX);
static PROG_6_PREV: AtomicUsize = AtomicUsize::new(usize::MAX);
static DYN_1_END: AtomicUsize = AtomicUsize::new(usize::MAX);
static DYN_2_END: AtomicUsize = AtomicUsize::new(usize::MAX);
static DYN_3_END: AtomicUsize = AtomicUsize::new(usize::MAX);
static DYN_4_END: AtomicUsize = AtomicUsize::new(usize::MAX);
static DYN_5_END: AtomicUsize = AtomicUsize::new(usize::MAX);
static DYN_6_END: AtomicUsize = AtomicUsize::new(usize::MAX);
static DYN_7_END: AtomicUsize = AtomicUsize::new(usize::MAX);
static DYN_8_END: AtomicUsize = AtomicUsize::new(usize::MAX);

pub trait Callbacks {
    fn quit(&mut self);
    fn action(&mut self, args: &[&str]);
    fn click(&mut self);
    fn nav(&mut self, args: &[&str]);
}

pub fn to_menu(name: &str) -> Option<Menu> {
    match name {
        "ActiveStyle" => Some(Menu::ActiveStyle),
        "AlignStyle" => Some(Menu::AlignStyle),
        "Alignment" => Some(Menu::Alignment),
        "Borders" => Some(Menu::Borders),
        "CellStyle" => Some(Menu::CellStyle),
        "Clickable" => Some(Menu::Clickable),
        "Cols" => Some(Menu::Cols),
        "Complex" => Some(Menu::Complex),
        "ContainerBg" => Some(Menu::ContainerBg),
        "ContainerBorder" => Some(Menu::ContainerBorder),
        "DynAlign" => Some(Menu::DynAlign),
        "DynUpdate" => Some(Menu::DynUpdate),
        "Dynamic" => Some(Menu::Dynamic),
        "Fixed" => Some(Menu::Fixed),
        "FlushCells" => Some(Menu::FlushCells),
        "FocusDisable" => Some(Menu::FocusDisable),
        "FocusGroups" => Some(Menu::FocusGroups),
        "Focusable" => Some(Menu::Focusable),
        "FontIcons" => Some(Menu::FontIcons),
        "Hello" => Some(Menu::Hello),
        "Icons" => Some(Menu::Icons),
        "LeafStyle" => Some(Menu::LeafStyle),
        "Margin" => Some(Menu::Margin),
        "MultilineAlign" => Some(Menu::MultilineAlign),
        "Overload" => Some(Menu::Overload),
        "Pad" => Some(Menu::Pad),
        "Popup" => Some(Menu::Popup),
        "Progress" => Some(Menu::Progress),
        "Rows" => Some(Menu::Rows),
        "Weighted" => Some(Menu::Weighted),
        _ => None,
    }
}

pub fn update_events<C: Callbacks>(events: &[InputEvent], state: &mut C) {
    for ev in events {
        if let InputEvent::Quit = ev { state.quit(); return; }
    }
    match *CURRENT_MENU.lock().unwrap() {
        Some(Menu::ActiveStyle) => update_events_activestyle(events, state),
        Some(Menu::AlignStyle) => update_events_alignstyle(events, state),
        Some(Menu::Alignment) => update_events_alignment(events, state),
        Some(Menu::Borders) => update_events_borders(events, state),
        Some(Menu::CellStyle) => update_events_cellstyle(events, state),
        Some(Menu::Clickable) => update_events_clickable(events, state),
        Some(Menu::Cols) => update_events_cols(events, state),
        Some(Menu::Complex) => update_events_complex(events, state),
        Some(Menu::ContainerBg) => update_events_containerbg(events, state),
        Some(Menu::ContainerBorder) => update_events_containerborder(events, state),
        Some(Menu::DynAlign) => update_events_dynalign(events, state),
        Some(Menu::DynUpdate) => update_events_dynupdate(events, state),
        Some(Menu::Dynamic) => update_events_dynamic(events, state),
        Some(Menu::Fixed) => update_events_fixed(events, state),
        Some(Menu::FlushCells) => update_events_flushcells(events, state),
        Some(Menu::FocusDisable) => update_events_focusdisable(events, state),
        Some(Menu::FocusGroups) => update_events_focusgroups(events, state),
        Some(Menu::Focusable) => update_events_focusable(events, state),
        Some(Menu::FontIcons) => update_events_fonticons(events, state),
        Some(Menu::Hello) => update_events_hello(events, state),
        Some(Menu::Icons) => update_events_icons(events, state),
        Some(Menu::LeafStyle) => update_events_leafstyle(events, state),
        Some(Menu::Margin) => update_events_margin(events, state),
        Some(Menu::MultilineAlign) => update_events_multilinealign(events, state),
        Some(Menu::Overload) => update_events_overload(events, state),
        Some(Menu::Pad) => update_events_pad(events, state),
        Some(Menu::Popup) => update_events_popup(events, state),
        Some(Menu::Progress) => update_events_progress(events, state),
        Some(Menu::Rows) => update_events_rows(events, state),
        Some(Menu::Weighted) => update_events_weighted(events, state),
        None => {}
    }
}

pub fn update_menu(backend: &mut dyn Backend, menu: Menu) {
    let mut current = CURRENT_MENU.lock().unwrap();
    if *current != Some(menu) {
        *current = Some(menu);
        drop(current);
        *FOCUSED.lock().unwrap() = None;
        *LAST_DRAWN_FOCUS.lock().unwrap() = None;
        ACTIVE.lock().unwrap().clear();
        LAST_DRAWN_ACTIVE.lock().unwrap().clear();
        PROG_1_PREV.store(usize::MAX, Ordering::Relaxed);
        PROG_2_PREV.store(usize::MAX, Ordering::Relaxed);
        PROG_3_PREV.store(usize::MAX, Ordering::Relaxed);
        PROG_4_PREV.store(usize::MAX, Ordering::Relaxed);
        PROG_5_PREV.store(usize::MAX, Ordering::Relaxed);
        PROG_6_PREV.store(usize::MAX, Ordering::Relaxed);
        DYN_1_END.store(usize::MAX, Ordering::Relaxed);
        DYN_2_END.store(usize::MAX, Ordering::Relaxed);
        DYN_3_END.store(usize::MAX, Ordering::Relaxed);
        DYN_4_END.store(usize::MAX, Ordering::Relaxed);
        DYN_5_END.store(usize::MAX, Ordering::Relaxed);
        DYN_6_END.store(usize::MAX, Ordering::Relaxed);
        DYN_7_END.store(usize::MAX, Ordering::Relaxed);
        DYN_8_END.store(usize::MAX, Ordering::Relaxed);
        match menu {
            Menu::ActiveStyle => draw_activestyle(backend),
            Menu::AlignStyle => draw_alignstyle(backend),
            Menu::Alignment => draw_alignment(backend),
            Menu::Borders => draw_borders(backend),
            Menu::CellStyle => draw_cellstyle(backend),
            Menu::Clickable => draw_clickable(backend),
            Menu::Cols => draw_cols(backend),
            Menu::Complex => draw_complex(backend),
            Menu::ContainerBg => draw_containerbg(backend),
            Menu::ContainerBorder => draw_containerborder(backend),
            Menu::DynAlign => draw_dynalign(backend),
            Menu::DynUpdate => draw_dynupdate(backend),
            Menu::Dynamic => draw_dynamic(backend),
            Menu::Fixed => draw_fixed(backend),
            Menu::FlushCells => draw_flushcells(backend),
            Menu::FocusDisable => draw_focusdisable(backend),
            Menu::FocusGroups => draw_focusgroups(backend),
            Menu::Focusable => draw_focusable(backend),
            Menu::FontIcons => draw_fonticons(backend),
            Menu::Hello => draw_hello(backend),
            Menu::Icons => draw_icons(backend),
            Menu::LeafStyle => draw_leafstyle(backend),
            Menu::Margin => draw_margin(backend),
            Menu::MultilineAlign => draw_multilinealign(backend),
            Menu::Overload => draw_overload(backend),
            Menu::Pad => draw_pad(backend),
            Menu::Popup => draw_popup(backend),
            Menu::Progress => draw_progress(backend),
            Menu::Rows => draw_rows(backend),
            Menu::Weighted => draw_weighted(backend),
        }
    }
}

pub fn force_redraw() {
    *CURRENT_MENU.lock().unwrap() = None;
}

pub fn update_params(backend: &mut dyn Backend, changes: &[(&str, &str)]) {
    match *CURRENT_MENU.lock().unwrap() {
        Some(Menu::ActiveStyle) => update_params_activestyle(backend, changes),
        Some(Menu::AlignStyle) => update_params_alignstyle(backend, changes),
        Some(Menu::Alignment) => update_params_alignment(backend, changes),
        Some(Menu::Borders) => update_params_borders(backend, changes),
        Some(Menu::CellStyle) => update_params_cellstyle(backend, changes),
        Some(Menu::Clickable) => update_params_clickable(backend, changes),
        Some(Menu::Cols) => update_params_cols(backend, changes),
        Some(Menu::Complex) => update_params_complex(backend, changes),
        Some(Menu::ContainerBg) => update_params_containerbg(backend, changes),
        Some(Menu::ContainerBorder) => update_params_containerborder(backend, changes),
        Some(Menu::DynAlign) => update_params_dynalign(backend, changes),
        Some(Menu::DynUpdate) => update_params_dynupdate(backend, changes),
        Some(Menu::Dynamic) => update_params_dynamic(backend, changes),
        Some(Menu::Fixed) => update_params_fixed(backend, changes),
        Some(Menu::FlushCells) => update_params_flushcells(backend, changes),
        Some(Menu::FocusDisable) => update_params_focusdisable(backend, changes),
        Some(Menu::FocusGroups) => update_params_focusgroups(backend, changes),
        Some(Menu::Focusable) => update_params_focusable(backend, changes),
        Some(Menu::FontIcons) => update_params_fonticons(backend, changes),
        Some(Menu::Hello) => update_params_hello(backend, changes),
        Some(Menu::Icons) => update_params_icons(backend, changes),
        Some(Menu::LeafStyle) => update_params_leafstyle(backend, changes),
        Some(Menu::Margin) => update_params_margin(backend, changes),
        Some(Menu::MultilineAlign) => update_params_multilinealign(backend, changes),
        Some(Menu::Overload) => update_params_overload(backend, changes),
        Some(Menu::Pad) => update_params_pad(backend, changes),
        Some(Menu::Popup) => update_params_popup(backend, changes),
        Some(Menu::Progress) => update_params_progress(backend, changes),
        Some(Menu::Rows) => update_params_rows(backend, changes),
        Some(Menu::Weighted) => update_params_weighted(backend, changes),
        None => {}
    }
    backend.flush();
}

