    backend.blit(atlas_1(), 10, 10, "[29/30] Active Styling");
    backend.fill_rect(0, 40, 800, 50, rgb!(0, 0, 0));
    backend.blit(atlas_2(), 10, 44, "active={border=...}: app-controlled");
    backend.blit(atlas_2(), 10, 66, "style via set_active(text, bool).");
    backend.fill_rect(104, 94, 192, 52, rgb!(30, 80, 180));
