    { let tw = atlas_4().text_width("Option B");
      backend.blit(atlas_4(), 292 + 214_usize.saturating_sub(tw) / 2, 216, "Option B"); }
    backend.fill_rect(272, 156, 254, 1, rgb!(100, 100, 100));
