fn update_params_dynalign(backend: &mut dyn Backend, changes: &[(&str, &str)]) {
    if changes.iter().any(|&(n, _)| n == "parameter One" || n == "parameter Two" || n == "parameter Three") {
        for &(name, val) in changes {
            if name == "parameter One" {
                let end_x = backend.blit_clipped(atlas_5(), 11, 189, val, 789);
                let prev = DYN_1_END.swap(end_x, Ordering::Relaxed);
                if prev != usize::MAX && prev > end_x {
                    backend.fill_rect(end_x, 189, prev - end_x, 32, rgb!(0, 0, 0));
                }
            }
            if name == "parameter Two" {
                let a = atlas_5();
                let prev = DYN_2_END.load(Ordering::Relaxed);
                let clear_w = if prev == usize::MAX { 778 } else { prev.saturating_sub(11) };
                backend.fill_rect(11, 299, clear_w, 32, rgb!(0, 0, 0));
                let tw = a.text_width(val);
                let bx = 11 + (778_usize.saturating_sub(tw)) / 2;
                let end_x = backend.blit(a, bx, 299, val);
                DYN_2_END.store(end_x, Ordering::Relaxed);
            }
            if name == "parameter Three" {
                let a = atlas_5();
                let prev = DYN_3_END.load(Ordering::Relaxed);
                let clear_w = if prev == usize::MAX { 778 } else { prev.saturating_sub(11) };
                backend.fill_rect(11, 409, clear_w, 32, rgb!(0, 0, 0));
                let tw = a.text_width(val);
                let bx = 11 + 778_usize.saturating_sub(tw);
                let end_x = backend.blit(a, bx, 409, val);
                DYN_3_END.store(end_x, Ordering::Relaxed);
            }
        }
    }
    {
        let focused = *FOCUSED.lock().unwrap();
        let mut last = LAST_DRAWN_FOCUS.lock().unwrap();
        if *last != focused {
            let prev = *last;
            *last = focused;
            drop(last);
            draw_focus_dynalign(backend, prev, focused);
        }
    }
}

