pub const FMT_PARAMS: &[&str] = &[];

/// Format a parameter value using metadata from params.txt.
/// Returns None if the parameter has no built-in formatting.
pub fn format_param(_name: &str, _val: &str) -> Option<String> { None }

pub fn focused_adjust() -> Option<(&'static str, f64, f64)> {
    None
}

pub fn set_focused(label: &str) {
    let menu = *CURRENT_MENU.lock().unwrap();
    let idx = match (menu, label) {
        (Some(Menu::FocusGroups), "parameter One") => Some(50),
        _ => None,
    };
    *FOCUSED.lock().unwrap() = idx;
}

pub fn clear_focused() {
    *FOCUSED.lock().unwrap() = None;
}

pub fn get_focused() -> Option<usize> {
    *FOCUSED.lock().unwrap()
}

pub fn set_focused_raw(idx: Option<usize>) {
    *FOCUSED.lock().unwrap() = idx;
}

pub fn set_active(id: &str, active: bool) {
    let menu = *CURRENT_MENU.lock().unwrap();
    let idx = match (menu, id) {
        (Some(Menu::ActiveStyle), "Option A") => Some(1),
        (Some(Menu::ActiveStyle), "Option B") => Some(2),
        (Some(Menu::ActiveStyle), "Option C") => Some(3),
        _ => None,
    };
    if let Some(i) = idx {
        let mut set = ACTIVE.lock().unwrap();
        if active { set.insert(i); } else { set.remove(&i); }
    }
}

pub fn clear_all_active() {
    ACTIVE.lock().unwrap().clear();
}

pub fn label_bounds(label: &str) -> Option<(usize, usize, usize, usize)> {
    let menu = *CURRENT_MENU.lock().unwrap();
    match (menu, label) {
        (Some(Menu::DynAlign), "parameter One") => Some((0, 150, 800, 110)),
        (Some(Menu::DynAlign), "parameter Two") => Some((0, 260, 800, 110)),
        (Some(Menu::DynAlign), "parameter Three") => Some((0, 370, 800, 110)),
        (Some(Menu::DynUpdate), "parameter One") => Some((400, 150, 400, 165)),
        (Some(Menu::DynUpdate), "parameter Two") => Some((400, 315, 400, 165)),
        (Some(Menu::Dynamic), "parameter One") => Some((0, 150, 800, 165)),
        (Some(Menu::Dynamic), "parameter Two") => Some((0, 315, 800, 165)),
        (Some(Menu::Progress), "parameter One") => Some((400, 370, 400, 110)),
        _ => None,
    }
}

